#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <string.h>

#define MAX_PHYS_PAGES (1U << 20)

typedef void (*trap_handler_t)(ExceptionInfo *);

static trap_handler_t trap_vector[TRAP_VECTOR_SIZE];
static struct pte region0_page_table[PAGE_TABLE_LEN];
static struct pte region1_page_table[PAGE_TABLE_LEN];

static unsigned char frame_in_use[MAX_PHYS_PAGES];
static unsigned int num_phys_pages;

static int vm_enabled;
static void *kernel_brk;

static void
panic_trap(ExceptionInfo *info)
{
    int vector = -1;
    int code = 0;

    if (info != NULL) {
        vector = info->vector;
        code = info->code;
    }

    TracePrintf(0, "Unhandled trap/exception vector=%d code=%d\n", vector, code);
    Halt();
}

static void
mark_frame_used(unsigned int pfn)
{
    if (pfn < num_phys_pages) {
        frame_in_use[pfn] = 1;
    }
}

static void
mark_range_used(unsigned long start, unsigned long end)
{
    unsigned long addr;
    unsigned long first_page;
    unsigned long last_page_exclusive;

    if (end <= start) {
        return;
    }

    first_page = DOWN_TO_PAGE(start);
    last_page_exclusive = UP_TO_PAGE(end);
    for (addr = first_page; addr < last_page_exclusive; addr += PAGESIZE) {
        mark_frame_used((unsigned int)(addr >> PAGESHIFT));
    }
}

static int
alloc_frame(unsigned int *pfn_out)
{
    unsigned int pfn;

    for (pfn = 0; pfn < num_phys_pages; pfn++) {
        if (!frame_in_use[pfn]) {
            frame_in_use[pfn] = 1;
            *pfn_out = pfn;
            return 0;
        }
    }

    return -1;
}

static void
free_frame(unsigned int pfn)
{
    if (pfn < num_phys_pages) {
        frame_in_use[pfn] = 0;
    }
}

static void
map_region0_kernel_stack(void)
{
    unsigned long va;

    for (va = KERNEL_STACK_BASE; va < KERNEL_STACK_LIMIT; va += PAGESIZE) {
        unsigned int vpn = (unsigned int)(va >> PAGESHIFT);
        region0_page_table[vpn].valid = 1;
        region0_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
        region0_page_table[vpn].uprot = PROT_NONE;
        region0_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
    }
}

static void
map_initial_region1(void *orig_brk)
{
    unsigned long text_end;
    unsigned long heap_end;
    unsigned long va;

    text_end = (unsigned long)&_etext;
    heap_end = (unsigned long)UP_TO_PAGE(orig_brk);

    for (va = VMEM_1_BASE; va < text_end; va += PAGESIZE) {
        unsigned int vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
        region1_page_table[vpn].valid = 1;
        region1_page_table[vpn].kprot = PROT_READ | PROT_EXEC;
        region1_page_table[vpn].uprot = PROT_NONE;
        region1_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
    }

    for (va = text_end; va < heap_end; va += PAGESIZE) {
        unsigned int vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
        region1_page_table[vpn].valid = 1;
        region1_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
        region1_page_table[vpn].uprot = PROT_NONE;
        region1_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
    }
}

static void
init_trap_vector(void)
{
    int i;

    for (i = 0; i < TRAP_VECTOR_SIZE; i++) {
        trap_vector[i] = NULL;
    }

    trap_vector[TRAP_KERNEL] = panic_trap;
    trap_vector[TRAP_CLOCK] = panic_trap;
    trap_vector[TRAP_ILLEGAL] = panic_trap;
    trap_vector[TRAP_MEMORY] = panic_trap;
    trap_vector[TRAP_MATH] = panic_trap;
    trap_vector[TRAP_TTY_RECEIVE] = panic_trap;
    trap_vector[TRAP_TTY_TRANSMIT] = panic_trap;
#ifdef _LAB3
    trap_vector[TRAP_DISK] = panic_trap;
#endif
}

static void
init_frame_allocator(unsigned int pmem_size, void *orig_brk)
{
    if ((pmem_size >> PAGESHIFT) > MAX_PHYS_PAGES) {
        num_phys_pages = MAX_PHYS_PAGES;
    } else {
        num_phys_pages = pmem_size >> PAGESHIFT;
    }

    memset(frame_in_use, 0, sizeof(frame_in_use));

    mark_range_used(KERNEL_STACK_BASE, KERNEL_STACK_LIMIT);
    mark_range_used(VMEM_1_BASE, (unsigned long)UP_TO_PAGE(orig_brk));
}

/*
 * KernelStart - Initialize the Yalnix kernel.
 *
 * Called by the hardware boot sequence to initialize the kernel.
 * Must set up virtual memory, create the idle and init processes,
 * set up trap handlers, and begin running user processes.
 */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    (void)cmd_args;

    kernel_brk = orig_brk;
    vm_enabled = 0;

    memset(region0_page_table, 0, sizeof(region0_page_table));
    memset(region1_page_table, 0, sizeof(region1_page_table));

    init_trap_vector();
    map_region0_kernel_stack();
    map_initial_region1(orig_brk);
    init_frame_allocator(pmem_size, orig_brk);

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)trap_vector);
    WriteRegister(REG_PTR0, (RCS421RegVal)region0_page_table);
    WriteRegister(REG_PTR1, (RCS421RegVal)region1_page_table);
    WriteRegister(REG_VM_ENABLE, 1);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_ALL);

    vm_enabled = 1;

    (void)info;
}

/*
 * SetKernelBrk - Adjust the kernel heap break.
 *
 * Called by malloc/free in the kernel to grow/shrink the heap.
 * Before virtual memory is enabled, simply track the break.
 * After VM is enabled, must allocate/free physical pages.
 */
int
SetKernelBrk(void *addr)
{
    unsigned long old_brk;
    unsigned long new_brk;
    unsigned long old_end_page;
    unsigned long new_end_page;
    unsigned long va;

    if (addr == NULL) {
        return -1;
    }

    old_brk = (unsigned long)kernel_brk;
    new_brk = (unsigned long)addr;

    if (new_brk < VMEM_1_BASE || new_brk > VMEM_1_LIMIT) {
        return -1;
    }

    if (new_brk < old_brk) {
        return -1;
    }

    if (!vm_enabled) {
        kernel_brk = addr;
        return 0;
    }

    old_end_page = (unsigned long)UP_TO_PAGE(old_brk);
    new_end_page = (unsigned long)UP_TO_PAGE(new_brk);

    for (va = old_end_page; va < new_end_page; va += PAGESIZE) {
        unsigned int pfn;
        unsigned int vpn;

        if (alloc_frame(&pfn) < 0) {
            unsigned long rollback_va;
            for (rollback_va = old_end_page; rollback_va < va; rollback_va += PAGESIZE) {
                unsigned int rb_vpn = (unsigned int)((rollback_va - VMEM_1_BASE) >> PAGESHIFT);
                if (region1_page_table[rb_vpn].valid) {
                    free_frame(region1_page_table[rb_vpn].pfn);
                    memset(&region1_page_table[rb_vpn], 0, sizeof(struct pte));
                }
            }
            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
            return -1;
        }

        vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
        region1_page_table[vpn].valid = 1;
        region1_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
        region1_page_table[vpn].uprot = PROT_NONE;
        region1_page_table[vpn].pfn = pfn;
    }

    if (new_end_page != old_end_page) {
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    }

    kernel_brk = addr;
    return 0;
}
